  5→//! Nominate command - create a new Heat
  6→//!
  7→//! This module provides the Args struct and handler for the jjx_nominate command.
  8→
  9→use std::path::PathBuf;
 10→use std::collections::BTreeMap;
 11→
 12→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
 13→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_NominateArgs as LibNominateArgs};
 14→use crate::jjrc_core::jjrc_timestamp_from_env;
 15→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 16→
 17→/// Arguments for jjx_nominate command
 18→#[derive(clap::Args, Debug)]
 19→pub struct jjrx_NominateArgs {
 20→    /// Path to the Gallops JSON file
 21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 22→    pub file: PathBuf,
 23→
 24→    /// Kebab-case display name for the Heat
 25→    #[arg(long, short = 's')]
 26→    pub silks: String,
 27→}
 28→
 29→/// Handler for jjx_nominate command
 30→pub fn jjrx_run_nominate(args: jjrx_NominateArgs) -> i32 {
 31→    use std::path::Path;
 32→
 33→    // Acquire lock FIRST - fail fast if another operation is in progress
 34→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 35→        Ok(l) => l,
 36→        Err(e) => {
 37→            eprintln!("jjx_nominate: error: {}", e);
 38→            return 1;
 39→        }
 40→    };
 41→
 42→    let mut gallops = if args.file.exists() {
 43→        match Gallops::jjrg_load(&args.file) {
 44→            Ok(g) => g,
 45→            Err(e) => {
 46→                eprintln!("jjx_nominate: error loading Gallops: {}", e);
 47→                return 1;
 48→            }
 49→        }
 50→    } else {
 51→        if let Some(parent) = args.file.parent() {
 52→            if let Err(e) = std::fs::create_dir_all(parent) {
 53→                eprintln!("jjx_nominate: error creating directory: {}", e);
 54→                return 1;
 55→            }
 56→        }
 57→        Gallops {
 58→            next_heat_seed: "AA".to_string(),
 59→            heat_order: vec![],
 60→            heats: BTreeMap::new(),
 61→        }
 62→    };
 63→
 64→    let base_path = args.file.parent()
 65→        .and_then(|p| p.parent())
 66→        .and_then(|p| p.parent())
 67→        .unwrap_or(Path::new("."));
 68→
 69→    let silks = args.silks.clone();
 70→    let nominate_args = LibNominateArgs {
 71→        silks: args.silks,
 72→        created: jjrc_timestamp_from_env(),
 73→    };
 74→
 75→    match gallops.jjrg_nominate(nominate_args, base_path) {
 76→        Ok(result) => {
 77→            let fm = Firemark::jjrf_parse(&result.firemark).expect("nominate returned invalid firemark");
 78→            let message = format_heat_message(&fm, HeatAction::Nominate, &silks);
 79→
 80→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
 81→                Ok(hash) => {
 82→                    eprintln!("jjx_nominate: committed {}", &hash[..8]);
 83→                }
 84→                Err(e) => {
 85→                    eprintln!("jjx_nominate: error: {}", e);
 86→                    return 1;
 87→                }
 88→            }
 89→
 90→            println!("{}", result.firemark);
 91→            0
 92→        }
 93→        Err(e) => {
 94→            eprintln!("jjx_nominate: error: {}", e);
 95→            1
 96→        }
 97→    }
 98→    // lock released here
 99→}
