 5→//! JJK chalk command - empty commits marking steeplechase events
 6→//!
 7→//! The chalk command creates empty commits with special formatting for tracking
 8→//! steeplechase events like approach, wrap, fly, or heat-level discussions.
 9→
10→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark};
11→use crate::jjrn_notch::{jjrn_ChalkMarker as ChalkMarker, jjrn_format_chalk_message, jjrn_format_heat_discussion};
12→
13→/// Arguments for jjx_chalk command
14→#[derive(clap::Args, Debug)]
15→pub struct jjrx_ChalkArgs {
16→    /// Identity: Coronet (pace-level) or Firemark (heat-level discussion only)
17→    pub identity: String,
18→
19→    /// Marker type: A(pproach), W(rap), F(ly), d(iscussion)
20→    #[arg(long)]
21→    pub marker: String,
22→
23→    /// Marker description text
24→    #[arg(long)]
25→    pub description: String,
26→}
27→
28→/// Run the chalk command - create steeplechase marker commit
29→pub fn jjrx_run_chalk(args: jjrx_ChalkArgs) -> i32 {
30→    let marker = match ChalkMarker::jjrn_parse(&args.marker) {
31→        Ok(m) => m,
32→        Err(e) => {
33→            eprintln!("jjx_chalk: error: {}", e);
34→            return 1;
35→        }
36→    };
37→
38→    // Try parsing as Coronet first (5 base64 chars), then as Firemark (2 base64 chars)
39→    let identity = args.identity.strip_prefix('₢').or_else(|| args.identity.strip_prefix('₣')).unwrap_or(&args.identity);
40→
41→    let message = if identity.len() == 5 {
42→        // Coronet - pace-level chalk
43→        let coronet = match Coronet::jjrf_parse(&args.identity) {
44→            Ok(c) => c,
45→            Err(e) => {
46→                eprintln!("jjx_chalk: error: {}", e);
47→                return 1;
48→            }
49→        };
50→        jjrn_format_chalk_message(&coronet, marker, &args.description)
51→    } else if identity.len() == 2 {
52→        // Firemark - heat-level (discussion, session)
53→        if marker.jjrn_requires_pace() {
54→            eprintln!("jjx_chalk: error: {} marker requires a Coronet (pace identity), not a Firemark", marker.jjrn_as_str());
55→            return 1;
56→        }
57→        let firemark = match Firemark::jjrf_parse(&args.identity) {
58→            Ok(fm) => fm,
59→            Err(e) => {
60→                eprintln!("jjx_chalk: error: {}", e);
61→                return 1;
62→            }
63→        };
64→
65→        jjrn_format_heat_discussion(&firemark, &args.description)
66→    } else {
67→        eprintln!("jjx_chalk: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
68→        return 1;
69→    };
70→
71→    let commit_args = vvc::vvcc_CommitArgs {
72→        prefix: None,
73→        message: Some(message),
74→        allow_empty: true,
75→        no_stage: true,
76→        size_limit: vvc::VVCG_SIZE_LIMIT,
77→        warn_limit: vvc::VVCG_WARN_LIMIT,
78→    };
79→
80→    vvc::commit(&commit_args)
81→}
