  5→//! Furlough command - change Heat status or rename
  6→//!
  7→//! Supports toggling between racing/stabled status and/or renaming a Heat.
  8→
  9→use std::path::PathBuf;
 10→
 11→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_FurloughArgs as LibFurloughArgs};
 13→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 14→
 15→/// Arguments for jjx_furlough command
 16→#[derive(clap::Args, Debug)]
 17→pub struct jjrfu_FurloughArgs {
 18→    /// Path to the Gallops JSON file
 19→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 20→    pub file: PathBuf,
 21→
 22→    /// Target Heat identity (Firemark)
 23→    pub firemark: String,
 24→
 25→    /// Set status to racing
 26→    #[arg(long, conflicts_with = "stabled")]
 27→    pub racing: bool,
 28→
 29→    /// Set status to stabled
 30→    #[arg(long, conflicts_with = "racing")]
 31→    pub stabled: bool,
 32→
 33→    /// New silks (rename heat)
 34→    #[arg(long, short = 's')]
 35→    pub silks: Option<String>,
 36→}
 37→
 38→/// Handler for jjx_furlough command
 39→pub fn jjrfu_run_furlough(args: jjrfu_FurloughArgs) -> i32 {
 40→    // Acquire lock FIRST - fail fast if another operation is in progress
 41→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 42→        Ok(l) => l,
 43→        Err(e) => {
 44→            eprintln!("jjx_furlough: error: {}", e);
 45→            return 1;
 46→        }
 47→    };
 48→
 49→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 50→        Ok(g) => g,
 51→        Err(e) => {
 52→            eprintln!("jjx_furlough: error loading Gallops: {}", e);
 53→            return 1;
 54→        }
 55→    };
 56→
 57→    // Build description for commit message
 58→    let mut changes = Vec::new();
 59→    if args.racing {
 60→        changes.push("racing".to_string());
 61→    } else if args.stabled {
 62→        changes.push("stabled".to_string());
 63→    }
 64→    if let Some(ref silks) = args.silks {
 65→        changes.push(format!("silks={}", silks));
 66→    }
 67→    let description = changes.join(", ");
 68→
 69→    let firemark_str = args.firemark.clone();
 70→    let furlough_args = LibFurloughArgs {
 71→        firemark: args.firemark,
 72→        racing: args.racing,
 73→        stabled: args.stabled,
 74→        silks: args.silks,
 75→    };
 76→
 77→    match gallops.jjrg_furlough(furlough_args) {
 78→        Ok(()) => {
 79→            let fm = Firemark::jjrf_parse(&firemark_str).expect("furlough given invalid firemark");
 80→            let message = format_heat_message(&fm, HeatAction::Furlough, &description);
 81→
 82→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 100000) {
 83→                Ok(hash) => {
 84→                    eprintln!("jjx_furlough: committed {}", &hash[..8]);
 85→                }
 86→                Err(e) => {
 87→                    eprintln!("jjx_furlough: error: {}", e);
 88→                    return 1;
 89→                }
 90→            }
 91→
 92→            0
 93→        }
 94→        Err(e) => {
 95→            eprintln!("jjx_furlough: error: {}", e);
 96→            1
 97→        }
 98→    }
 99→    // lock released here
100→}
