40→    };
41→
42→    // Try parsing as Coronet first (5 base64 chars), then as Firemark (2 base64 chars)
43→    let identity = args.identity.strip_prefix('₢').or_else(|| args.identity.strip_prefix('₣')).unwrap_or(&args.identity);
