65→                return (1, buf);
66→            }
67→        };
68→
69→        jjrn_format_heat_discussion(&firemark, &args.description)
70→    } else {
71→        eprintln!("jjx_chalk: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
72→        return (1, buf);
73→    };
74→
75→    let commit_args = vvc::vvcc_CommitArgs {
76→        prefix: None,
77→        message: Some(message),
78→        allow_empty: true,
79→        no_stage: true,
80→        size_limit: vvc::VVCG_SIZE_LIMIT,
81→        warn_limit: vvc::VVCG_WARN_LIMIT,
82→    };
83→
84→    let _ = buf; // buf unused for chalk (no stdout output), but signature requires it
85→    (vvc::commit(&commit_args), buf)
