15→
16→/// Arguments for jjx_chalk command
17→#[derive(clap::Args, Debug)]
18→pub struct jjrx_ChalkArgs {
19→    /// Identity: Coronet (pace-level) or Firemark (heat-level discussion only)
20→    pub identity: String,
21→
