 76→    };
 77→
 78→    // Save gallops
 79→    if let Err(e) = gallops.jjrg_save(&args.file) {
 80→        eprintln!("jjx_garland: error saving Gallops: {}", e);
 81→        return (1, buf);
 82→    }
 83→
 84→    // Parse both firemarks for commit file list
 85→    let old_fm = Firemark::jjrf_parse(&result.old_firemark).expect("garland returned invalid old firemark");
 86→    let new_fm = Firemark::jjrf_parse(&result.new_firemark).expect("garland returned invalid new firemark");
 87→
 88→    let gallops_path = args.file.to_string_lossy().to_string();
 89→    let old_paddock_path = jjri_paddock_path(old_fm.jjrf_as_str());
 90→    let new_paddock_path = jjri_paddock_path(new_fm.jjrf_as_str());
 91→
 92→    // Build commit message using heat-level Garland action
 93→    let commit_message = format_heat_message(
 94→        &old_fm,
 95→        HeatAction::Garland,
 96→        &format!("{} → {}", result.old_silks, result.new_silks)
 97→    );
 98→
 99→    let commit_args = vvc::vvcm_CommitArgs {
100→        files: vec![
101→            gallops_path,
102→            old_paddock_path,
103→            new_paddock_path,
104→        ],
105→        message: commit_message,
106→        size_limit: 100000,  // 100KB - paddock files can be large
107→        warn_limit: 50000,
108→    };
109→
110→    match vvc::machine_commit(&lock, &commit_args) {
111→        Ok(hash) => {
112→            eprintln!("jjx_garland: committed {}", &hash[..8]);
113→        }
114→        Err(e) => {
115→            eprintln!("jjx_garland: commit warning: {}", e);
116→        }
117→    }
118→
119→    // Output JSON result
120→    let output = serde_json::json!({
121→        "old_firemark": result.old_firemark,
122→        "old_silks": result.old_silks,
123→        "new_firemark": result.new_firemark,
124→        "new_silks": result.new_silks,
125→        "paces_transferred": result.paces_transferred,
126→        "paces_retained": result.paces_retained,
127→    });
128→
129→    match serde_json::to_string_pretty(&output) {
130→        Ok(json) => {
131→            let _ = writeln!(buf, "{}", json);
132→            (0, buf)
133→        }
134→        Err(e) => {
135→            eprintln!("jjx_garland: error serializing output: {}", e);
136→            (1, buf)
137→        }
138→    }
139→    // lock released here
140→}
141→
